 50→fun PlayerScreen(
 51→    videoPath: String,
 52→    subtitlePath: String?,
 53→    onBack: () -> Unit,
 54→    viewModel: PlayerViewModel = hiltViewModel()
 55→) {
 56→    val uiState by viewModel.uiState.collectAsState()
 57→    val context = LocalContext.current
 58→    val listState = rememberLazyListState()
 59→    val coroutineScope = rememberCoroutineScope()
 60→
 61→    // 注册转录服务广播接收器
 62→    val transcriptionReceiver = remember {
 63→        object : BroadcastReceiver() {
 64→            override fun onReceive(context: Context?, intent: Intent?) {
 65→                when (intent?.action) {
 66→                    TranscriptionService.ACTION_PROGRESS -> {
 67→                        val segment = intent.getIntExtra(TranscriptionService.EXTRA_SEGMENT, 0)
 68→                        val total = intent.getIntExtra(TranscriptionService.EXTRA_TOTAL, 0)
 69→                        val progress = intent.getIntExtra(TranscriptionService.EXTRA_PROGRESS, 0)
 70→                        val message = intent.getStringExtra(TranscriptionService.EXTRA_MESSAGE) ?: ""
 71→                        val remaining = intent.getLongExtra(TranscriptionService.EXTRA_REMAINING, 0)
 72→                        viewModel.onTranscriptionProgress(segment, total, progress, message, remaining)
 73→                    }
 74→                    TranscriptionService.ACTION_QUEUE_UPDATE -> {
 75→                        // 队列状态更新（可选：显示队列中的其他视频数量）
 76→                        val queueSize = intent.getIntExtra(TranscriptionService.EXTRA_QUEUE_SIZE, 0)
 77→                        // 可以在这里更新 UI 显示队列信息
 78→                    }
 79→                    TranscriptionService.ACTION_COMPLETED -> {
 80→                        val success = intent.getBooleanExtra(TranscriptionService.EXTRA_SUCCESS, false)
 81→                        val detectedLang = intent.getStringExtra(TranscriptionService.EXTRA_DETECTED_LANG) ?: ""
 82→                        val subtitleCount = intent.getIntExtra(TranscriptionService.EXTRA_SUBTITLE_COUNT, 0)
 83→                        val error = intent.getStringExtra(TranscriptionService.EXTRA_ERROR)
 84→                        viewModel.onTranscriptionCompleted(videoPath, success, detectedLang, subtitleCount, error)
 85→                    }
 86→                }
 87→            }
 88→        }
 89→    }
 90→
 91→    // 注册和注销广播接收器
 92→    DisposableEffect(Unit) {
 93→        val progressFilter = IntentFilter(TranscriptionService.ACTION_PROGRESS)
 94→        val completedFilter = IntentFilter(TranscriptionService.ACTION_COMPLETED)
 95→        val queueFilter = IntentFilter(TranscriptionService.ACTION_QUEUE_UPDATE)
 96→        context.registerReceiver(transcriptionReceiver, progressFilter, android.content.Context.RECEIVER_NOT_EXPORTED)
 97→        context.registerReceiver(transcriptionReceiver, completedFilter, android.content.Context.RECEIVER_NOT_EXPORTED)
 98→        context.registerReceiver(transcriptionReceiver, queueFilter, android.content.Context.RECEIVER_NOT_EXPORTED)
 99→
100→        onDispose {
101→            context.unregisterReceiver(transcriptionReceiver)
102→        }
103→    }
104→
105→    // 绑定转录服务以检查状态
106→    var serviceBinder: TranscriptionService.LocalBinder? = null
107→    val serviceConnection = remember {
108→        object : ServiceConnection {
109→            override fun onServiceConnected(name: ComponentName?, service: IBinder?) {
110→                val binder = service as TranscriptionService.LocalBinder
111→                serviceBinder = binder
112→                // 获取服务当前状态并同步到 UI
113→                coroutineScope.launch {
114→                    binder.getService().serviceState.collect { state ->
115→                        when (state) {
116→                            is ServiceState.Transcribing -> {
117→                                viewModel.syncServiceState(
118→                                    isServiceTranscribing = true,
119→                                    segment = state.segment,
120→                                    total = state.total,
121→                                    progress = state.progress,
122→                                    message = state.message,
123→                                    remaining = 0
124→                                )
125→                            }
126→                            is ServiceState.Idle,
127→                            is ServiceState.Completed,
128→                            is ServiceState.Error -> {
129→                                // 服务不在转录状态，无需同步
130→                            }
131→                        }
132→                    }
133→                }
134→            }
135→
136→            override fun onServiceDisconnected(name: ComponentName?) {
137→                serviceBinder = null
138→            }
139→        }
140→    }
141→
142→    DisposableEffect(Unit) {
143→        val intent = Intent(context, TranscriptionService::class.java)
144→        context.bindService(intent, serviceConnection, Context.BIND_AUTO_CREATE)
145→
146→        onDispose {
147→            serviceBinder?.let { context.unbindService(serviceConnection) }
148→        }
149→    }
150→
151→    // ExoPlayer
152→    val exoPlayer = remember {
153→        ExoPlayer.Builder(context).build().apply {
154→            setMediaItem(MediaItem.fromUri(videoPath))
155→            prepare()
156→        }
157→    }
158→
159→    // Load subtitles
160→    LaunchedEffect(videoPath) {
161→        viewModel.loadSubtitles(videoPath, subtitlePath)
162→    }
163→
164→    // 30ms position polling (ported from renderer.js syncTimer)
165→    LaunchedEffect(exoPlayer) {
166→        while (isActive) {
167→            if (exoPlayer.isPlaying) {
168→                viewModel.updatePosition(exoPlayer.currentPosition)
169→            }
170→            delay(30)
