253→            if (uiState.mode == "learn") {
254→                // === Learning Mode ===
255→                // Current subtitle with karaoke highlighting
256→                Card(
257→                    modifier = Modifier.fillMaxWidth().padding(horizontal = 16.dp, vertical = 4.dp),
258→                    colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surfaceVariant)
259→                ) {
260→                    Column(modifier = Modifier.padding(16.dp)) {
