444→@Composable
445→fun DictationPanel(
446→    subtitle: SubtitleCue?,
447→    onSpeak: (String) -> Unit,
448→    onNext: () -> Unit,
449→    onLookup: (String) -> Unit
450→) {
451→    if (subtitle == null) {
452→        Box(Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
453→            Text("没有字幕可用", color = MaterialTheme.colorScheme.onSurfaceVariant)
454→        }
455→        return
456→    }
457→
458→    val words = subtitle.text.split(Regex("\\s+")).filter { it.isNotBlank() }
459→    val answers = remember(subtitle) { words.map { it.replace(Regex("[^\\p{L}\\p{M}'-]"), "") } }
460→    val inputs = remember(subtitle) { mutableStateListOf(*Array(words.size) { "" }) }
461→    val results = remember(subtitle) { mutableStateListOf(*Array(words.size) { "" }) }
462→
463→    Column(modifier = Modifier.fillMaxSize().padding(16.dp)) {
464→        // Word input boxes
465→        Card(modifier = Modifier.fillMaxWidth()) {
466→            Column(modifier = Modifier.padding(16.dp)) {
467→                Row(
468→                    modifier = Modifier.fillMaxWidth(),
469→                    horizontalArrangement = Arrangement.spacedBy(8.dp),
470→                    verticalAlignment = Alignment.CenterVertically
471→                ) {
472→                    words.forEachIndexed { i, word ->
473→                        Column(horizontalAlignment = Alignment.CenterHorizontally) {
474→                            OutlinedTextField(
475→                                value = inputs[i],
476→                                onValueChange = { inputs[i] = it },
477→                                modifier = Modifier.width((word.length * 14 + 30).coerceAtLeast(60).dp),
478→                                singleLine = true,
479→                                isError = results[i] == "wrong",
480→                                colors = OutlinedTextFieldDefaults.colors(
481→                                    focusedBorderColor = if (results[i] == "correct") Color.Green else MaterialTheme.colorScheme.primary
482→                                )
483→                            )
484→                            if (results[i] == "wrong") {
485→                                Text(answers[i], color = MaterialTheme.colorScheme.error, style = MaterialTheme.typography.labelSmall)
486→                            }
487→                            TextButton(onClick = { onLookup(word.replace(Regex("[^\\p{L}\\p{M}'-]"), "")) }) {
488→                                Text("查词", style = MaterialTheme.typography.labelSmall)
489→                            }
490→                        }
491→                    }
492→                }
493→            }
494→        }
495→
496→        Spacer(Modifier.height(12.dp))
497→
498→        // Control buttons
499→        Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
500→            Button(onClick = { onSpeak(subtitle.text) }) {
501→                Icon(Icons.Default.VolumeUp, null, Modifier.size(16.dp))
502→                Spacer(Modifier.width(4.dp))
503→                Text("朗读")
504→            }
505→            Button(onClick = {
506→                answers.forEachIndexed { i, answer ->
507→                    results[i] = if (inputs[i].trim().equals(answer, ignoreCase = true)) "correct" else "wrong"
508→                }
509→            }) {
510→                Icon(Icons.Default.Check, null, Modifier.size(16.dp))
511→                Spacer(Modifier.width(4.dp))
512→                Text("检查")
513→            }
514→            Button(onClick = {
515→                inputs.indices.forEach { inputs[it] = "" }
516→                results.indices.forEach { results[it] = "" }
517→                onNext()
518→            }) {
519→                Icon(Icons.Default.ArrowForward, null, Modifier.size(16.dp))
520→                Spacer(Modifier.width(4.dp))
521→                Text("下一句")
522→            }
523→        }
524→    }
525→}
