342→                            val aiDeferred = async { aiTranslateWord(word, context, lang, aiConfig) }
343→                            val online = onlineDeferred.await()
344→                            val translation = transDeferred.await()
345→                            val aiTrans = aiDeferred.await()
346→                            WordCardData(
347→                                word = word,
