349→                                translation = aiTrans ?: translation ?: "未找到释义",
350→                                definitions = online?.definitions ?: emptyList()
351→                            )
352→                        }
353→                        else -> {
354→                            val transDeferred = async { dictionaryService.translate(word, lang) }
355→                            val aiDeferred = async { aiTranslateWord(word, context, lang, aiConfig) }
356→                            val translation = transDeferred.await()
357→                            val aiTrans = aiDeferred.await()
358→                            WordCardData(
